mapper.select:
SELECT k.id, k.category, k.title, k.cover_url AS "coverUrl", k.video_id AS "videoId", k.video_account_id AS "videoAccountId", k.sort, k.status, k.create_time AS "createTime", k.update_time AS "updateTime" FROM knowledge k
AND (k.title LIKE CONCAT('%', #{params.keyword}, '%') OR k.category LIKE CONCAT('%', #{params.keyword}, '%'))
AND (k.title LIKE '%' || #{params.keyword} || '%' OR k.category LIKE '%' || #{params.keyword} || '%')
AND k.category = #{params.category}
AND k.status = #{params.status}
ORDER BY k.sort DESC, k.update_time DESC, k.id DESC
